import datetimefrom dataclasses import dataclassfrom app.repository.checkins import CheckinsRepository@dataclassclass CheckinsService:	checkin_repo: CheckinsRepository			async def set_checkin(self, habit_id: int) -> None:		await self.checkin_repo.set_checkin(habit_id=habit_id)			async def delete_checkin(self, habit_id: int, date: str):		date = self._covert_string_to_date(date_str=date)		await self.checkin_repo.delete_checkin(habit_id=habit_id, date=date)			def _covert_string_to_date(self, date_str: str) -> datetime.date:		try:			converted_date = datetime.datetime.strptime(date_str, "%Y-%m-%d")		except ValueError:			raise WrongDateFormat				return converted_date